-- Migration: diagnostic_eval_reports
-- Full clinical eval reports generated by Claude Opus 4.6
-- Each report contains structured JSON with deal breakers, frequency phases,
-- supplementation, Five Levers assessment, and patient-friendly analogies.

CREATE TABLE IF NOT EXISTS diagnostic_eval_reports (
  id                      UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  diagnostic_analysis_id  UUID NOT NULL REFERENCES diagnostic_analyses(id) ON DELETE CASCADE,
  patient_id              UUID NOT NULL REFERENCES patients(id) ON DELETE CASCADE,
  report_json             JSONB NOT NULL DEFAULT '{}',
  urgency_rating          NUMERIC(3,1),     -- 0.0–5.0 (5.0 = critical)
  deal_breaker_count      INTEGER,
  status                  TEXT NOT NULL DEFAULT 'pending'
    CHECK (status IN ('pending', 'processing', 'complete', 'error')),
  error_message           TEXT,
  created_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at              TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Indexes for common query patterns
CREATE INDEX idx_diagnostic_eval_reports_analysis
  ON diagnostic_eval_reports (diagnostic_analysis_id);

CREATE INDEX idx_diagnostic_eval_reports_patient
  ON diagnostic_eval_reports (patient_id);

CREATE INDEX idx_diagnostic_eval_reports_status
  ON diagnostic_eval_reports (status)
  WHERE status IN ('pending', 'processing');

-- Auto-update updated_at
CREATE OR REPLACE FUNCTION update_diagnostic_eval_reports_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER diagnostic_eval_reports_updated_at
  BEFORE UPDATE ON diagnostic_eval_reports
  FOR EACH ROW
  EXECUTE FUNCTION update_diagnostic_eval_reports_updated_at();

-- RLS: users can only see eval reports for their own patients
ALTER TABLE diagnostic_eval_reports ENABLE ROW LEVEL SECURITY;

-- Practitioners can see/insert reports for patients they own
CREATE POLICY "practitioners_own_eval_reports"
  ON diagnostic_eval_reports
  FOR ALL
  USING (
    patient_id IN (
      SELECT id FROM patients WHERE user_id = auth.uid()
    )
  )
  WITH CHECK (
    patient_id IN (
      SELECT id FROM patients WHERE user_id = auth.uid()
    )
  );

-- Service role (Python agent) bypasses RLS
-- (no explicit policy needed — service_role always bypasses)
